import './CalendarMobileContainer.scss';

import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import type { PopupsContextData } from ':helpers/popupsContext';
import { PopupsContext } from ':helpers/popupsContext';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useContext, useLayoutEffect, useState } from 'react';
import * as ReactDOM from 'react-dom';

import { Button } from '../../../../Button';
import { CalendarNavigationIcon } from '../../CalendarNavigationIcon';
import { useOnOutsideCalendarClick } from '../../hooks';
import type { CalendarMobileContainerProps } from './CalendarMobileContainer.types';

const [calendarClassName, calendarModifier, calendarBlockModifier] = getBEMClasses('dsb_calendar-mobile');
const [footerClassName] = calendarBlockModifier('footer');
const [headerClassName, headerModifier] = calendarBlockModifier('header');

export const CalendarMobileContext = React.createContext<{
	applicationElementID?: string;
	calendarElementID?: string;
	rootElement?: HTMLElement;
}>({});

export const CalendarMobileContainer: React.FC<CalendarMobileContainerProps> = ({
	className,
	datepickerRef,
	onOutsideClick,
	onClickSelectDates,
	onSaveClick,
	dataTestId = 'calendar-mobile-container',
	saveButtonTitle,
	children,
	viewYear,
	readonly,
}) => {
	const { applicationElementID, calendarElementID, rootElement: rootElementCntx } = useContext(CalendarMobileContext);
	const { applicationElementID: baseAppElementID, rootElement: rootElementDefaultCntx } =
		useContext<PopupsContextData>(PopupsContext);
	const [calendarElement, setCalendarElement] = useState<HTMLDivElement>(null);
	const [rootElement, setRootElement] = useState<HTMLElement>();
	const applicationRootElementId = applicationElementID || baseAppElementID || 'root';
	const elementID = calendarElementID || 'calendar-mobile';
	const element = rootElementCntx || rootElementDefaultCntx;

	useOnOutsideCalendarClick({
		calendarElement,
		datepickerElement: datepickerRef?.current,
		onOutsideClick,
		rootElement: element,
	});

	/**
	 * Устанавливает ref вручную. В противном случае ref пуст, так как цикл обновления после useLayoutEffect
	 * и рендера портала не запускается.
	 * @param node HTML нода для установки в качестве элемента календаря
	 */
	const handleRef = (node: HTMLDivElement): void => {
		setCalendarElement(node);
	};

	useLayoutEffect(() => {
		const mount = element || document.getElementById(applicationRootElementId);
		if (!mount) {
			throw new Error(`Application root element with ID "${applicationRootElementId}" not found`);
		}

		const createPortalRoot = (rootId: string): HTMLDivElement => {
			const rootElement = document.createElement('div');
			rootElement.id = rootId;
			rootElement.className = calendarModifier('wrapper');

			return rootElement;
		};

		const el = createPortalRoot(elementID);
		const elementRef = mount.appendChild(el);
		setRootElement(elementRef);

		return () => {
			el.remove();
		};
	}, [applicationRootElementId, elementID, element]);

	const footer = (
		<div className={footerClassName}>
			<Button variant="contained" onClick={onSaveClick || onClickSelectDates} size="medium">
				{saveButtonTitle || 'Сохранить'}
			</Button>
		</div>
	);

	const hasFooter = (onSaveClick || onClickSelectDates) && !readonly;

	const calendarContent = (
		<div ref={handleRef} className={classNames(calendarClassName, className)} data-testid={dataTestId}>
			<header className={headerClassName}>
				<CalendarNavigationIcon
					direction={Icons.NavArrowLeft}
					onClick={onOutsideClick ? onOutsideClick : null}
					dataTestId={`${dataTestId}-back`}
				/>
				<span className={headerModifier('title')} data-test-id={`${dataTestId}-select-year`}>
					{viewYear}
				</span>
			</header>
			{children}
			{hasFooter && footer}
		</div>
	);

	return (rootElement && ReactDOM.createPortal(calendarContent, rootElement)) || null;
};
